using Xunit; public sealed class CraftingLogicTests { [Fact] public void Crafting_RemovesIngredientsAndAddsOutput(){ StorageState st=new(); st.AddItem("wooden_plank",4,99); st.AddItem("metal",2,99); CraftRecipe r=new("r","Test",new[]{new CraftIngredient("wooden_plank",2),new CraftIngredient("metal",1)},"simple_medkit",1); CraftResult result=CraftingLogic.TryCraft(st,r,new InventoryItemDefinition("simple_medkit",5,0.5f),1); Assert.True(result.Succeeded); Assert.Equal(2,st.GetTotalAmount("wooden_plank")); Assert.Equal(1,st.GetTotalAmount("metal")); Assert.Equal(1,st.GetTotalAmount("simple_medkit")); } }